// Script Continued Below
function onLoad() {
   //Type appropriate comment here, and begin script below

	var msg = '';
	var toastMsg = '';
	var strSuspenseDate = g_form.getValue('suspense_date');
	var dteSuspenseDate = getDateFromFormat(strSuspenseDate, g_user_date_time_format);
	var strExternalDueDate = g_form.getValue('u_external_due_date');
	var dteExternalDueDate = getDateFromFormat(strExternalDueDate, g_user_date_time_format);

	// STRY0077867
	if(!g_form.getValue('parent')){
		if(g_form.getValue('tasking_authority.u_external_flag') == 'true'){
			if(dteSuspenseDate > dteExternalDueDate){
				g_form.showFieldMsg('suspense_date', getMessage('Suspense Date AFTER External Due Date'), 'error', true);
			}
		} else if(g_form.getValue('outbound') == 'true'){
			// STRY0077947
			if(dteExternalDueDate > dteSuspenseDate){
				g_form.showFieldMsg('u_external_due_date', getMessage('External Due Date is AFTER the Suspense Date'), 'error', true);
			}
		}
	} else if(g_form.getValue('outbound') == 'true'){
		// STRY0077947
		if(dteExternalDueDate > dteSuspenseDate){
			g_form.showFieldMsg('u_external_due_date', getMessage('External Due Date is AFTER the Suspense Date'), 'error', true);
		}
	}
	// STRY0077847
	if(g_scratchpad.taskSuspenseDateOlderThanParent){
		g_form.showFieldMsg('suspense_date', getMessage('Subtask Suspense Date AFTER Parent Task Suspense Date'), 'error', true);
	}
	// STRY0077855
	if(g_scratchpad.subtaskSuspenseDateOlderThanParent){
		g_form.showFieldMsg('suspense_date', getMessage('A Subtask has a Suspense Date AFter this Task'), 'error', true);
		if (typeof spModal != 'undefined' ) {
			var linkToPlatform = '../x_153465_discovert_route_task_instance.do?sys_id=' + g_form.getUniqueValue();
			toastMsg = getMessage('Portal Toast A Subtask has a Suspense Date After the Suspense Date on this Task');
			toastMsg = toastMsg.replace('doNotTranslageLinkToPlatform', linkToPlatform);
		}else{
			toastMsg = getMessage('Platform Toast A Subtask has a Suspense Date After the Suspense Date on this Task');
		}
		g_form.addErrorMessage(toastMsg);
	}

}
